# 사용자 프로필 수정 API 설계

## 1. 현재 프로젝트 구조 분석

기존 코드 파일이 없는 초기 프로젝트이므로, SKILL.md 컨벤션과 도메인(`maum` 카탈로그 하위 `profile`)을 기준으로 설계합니다.

확인된 컨벤션 기준:
- GraphQL Input 타입명: `{Action}{Domain}Input` (PascalCase)
- Mutation 명: camelCase 동사 시작
- Proto 필드명: `snake_case`
- 인증: `@PreAuthorize("hasAuthority('User')")` + `@UserId`
- 에러: `CustomGraphQLException` 경유

---

## 2. GraphQL 스키마 설계

파일 위치: `graphql/src/main/resources/graphql/profile.graphqls`

```graphql
# 프로필 수정 Mutation 입력 타입
# 모든 필드는 nullable - 전달된 필드만 수정하는 Partial Update 방식
input UpdateUserProfileInput {
    # 기본 정보
    nickname:       String          # 닉네임 (최대 20자)
    introduction:   String          # 자기소개 (최대 200자)
    profileImageId: ID              # 업로드된 이미지 ID (null이면 기본 이미지로 초기화)

    # 음성 통화 앱 특성 - 사용자 속성
    gender:         GenderType      # 성별 (MALE / FEMALE / OTHER)
    birthYear:      Int             # 출생 연도 (ex: 1995)
    regionCode:     String          # 지역 코드 (ex: "KR-11" 서울)

    # 관심사 태그 (최대 5개)
    interestTagIds: [ID!]
}

# 성별 열거형
enum GenderType {
    MALE
    FEMALE
    OTHER
}

# Mutation 응답 타입 - 수정 후 최신 프로필 반환
type UpdateUserProfilePayload {
    profile: UserProfile!
}

# 사용자 프로필 타입
type UserProfile {
    userId:         ID!
    nickname:       String!
    introduction:   String
    profileImageUrl: String         # CDN URL (null이면 기본 이미지)
    gender:         GenderType
    birthYear:      Int
    regionCode:     String
    interestTags:   [InterestTag!]!
    createdAt:      String!
    updatedAt:      String!
}

# 관심사 태그
type InterestTag {
    id:    ID!
    name:  String!
}

extend type Query {
    # 내 프로필 조회
    myProfile: UserProfile!
    # 타인 프로필 조회
    userProfile(userId: ID!): UserProfile
}

extend type Mutation {
    # 내 프로필 수정 (Partial Update - 전달한 필드만 수정)
    updateUserProfile(input: UpdateUserProfileInput!): UpdateUserProfilePayload!
}
```

### 설계 판단 근거

| 결정 | 이유 |
|------|------|
| Input 필드 전체 nullable | 프로필 수정은 일부 필드만 변경하는 Partial Update가 UX에 적합 |
| `UpdateUserProfilePayload` Wrapper 타입 | 향후 `errors`, `warnings` 등 메타 필드 확장 여지 확보 |
| `profileImageId` (ID) 수신, `profileImageUrl` (String) 반환 | 클라이언트는 업로드 ID 전달, 서버는 CDN URL 조합 후 반환 |
| `GenderType` enum | 문자열 오타 방지 및 클라이언트 타입 안전성 |
| `interestTagIds: [ID!]` | 전체 덮어쓰기 방식 (추가/삭제 구분 복잡도 제거) |

---

## 3. gRPC Proto 설계

파일 위치: `protobuf/src/main/proto/user/user_profile_service.proto`

```protobuf
syntax = "proto3";
package user;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.user";

service UserProfileService {
  rpc GetUserProfile(GetUserProfileRequest)       returns (GetUserProfileResponse);
  rpc UpdateUserProfile(UpdateUserProfileRequest) returns (UpdateUserProfileResponse);
}

// 프로필 조회 Request
message GetUserProfileRequest {
  string user_id = 1;
}

// 프로필 조회 Response
message GetUserProfileResponse {
  UserProfile profile = 1;
}

// 프로필 수정 Request
// has_* 패턴으로 null 전달 vs 미전달 구분 (Partial Update 지원)
message UpdateUserProfileRequest {
  string user_id         = 1;

  optional string nickname         = 2;
  optional string introduction     = 3;
  optional string profile_image_id = 4;  // null = 기본 이미지로 초기화
  optional GenderType gender       = 5;
  optional int32  birth_year       = 6;
  optional string region_code      = 7;

  // 전달 시 전체 덮어쓰기, 미전달 시 변경 없음
  repeated string interest_tag_ids = 8;
  bool update_interest_tags        = 9;  // interest_tag_ids 변경 의도 명시 플래그
}

// 프로필 수정 Response
message UpdateUserProfileResponse {
  UserProfile profile = 1;
}

// 공통 UserProfile 메시지
message UserProfile {
  string      user_id           = 1;
  string      nickname          = 2;
  string      introduction      = 3;
  string      profile_image_url = 4;
  GenderType  gender            = 5;
  int32       birth_year        = 6;
  string      region_code       = 7;
  repeated InterestTag interest_tags = 8;
  string      created_at        = 9;
  string      updated_at        = 10;
}

message InterestTag {
  string id   = 1;
  string name = 2;
}

enum GenderType {
  GENDER_TYPE_UNSPECIFIED = 0;
  GENDER_TYPE_MALE        = 1;
  GENDER_TYPE_FEMALE      = 2;
  GENDER_TYPE_OTHER       = 3;
}
```

