## 4. GraphQL Controller

파일 위치: `graphql/src/main/kotlin/com/maum/backend/controller/profile/UserProfileController.kt`

```kotlin
@Controller
class UserProfileController(
    private val userProfileService: UserProfileService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun myProfile(
        @UserId userId: String,
    ): UserProfileResponse {
        val response = userProfileService.getUserProfile(userId)
        return response.profile.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun userProfile(
        @Argument userId: String,
    ): UserProfileResponse? {
        val response = userProfileService.getUserProfile(userId)
        return response.profile?.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateUserProfile(
        @UserId userId: String,
        @Argument input: UpdateUserProfileInput,
    ): UpdateUserProfilePayload {
        val response = userProfileService.updateUserProfile(userId, input)
        return UpdateUserProfilePayload(profile = response.profile.toResponse())
    }
}
```

