## 5. GraphQL Service (gRPC Client)

파일 위치: `graphql/src/main/kotlin/com/maum/backend/service/profile/UserProfileService.kt`

```kotlin
@Service
class UserProfileService {

    @GrpcClient("user-grpc")
    private lateinit var stub: UserProfileServiceGrpc.UserProfileServiceBlockingStub

    fun getUserProfile(userId: String): GetUserProfileResponse {
        val request = GetUserProfileRequest.newBuilder()
            .setUserId(userId)
            .build()
        return try {
            stub.getUserProfile(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun updateUserProfile(
        userId: String,
        input: UpdateUserProfileInput,
    ): UpdateUserProfileResponse {
        val builder = UpdateUserProfileRequest.newBuilder()
            .setUserId(userId)

        // Partial Update: null이 아닌 필드만 set
        input.nickname?.let { builder.setNickname(it) }
        input.introduction?.let { builder.setIntroduction(it) }
        input.profileImageId?.let { builder.setProfileImageId(it) }
        input.gender?.let { builder.setGender(it.toProto()) }
        input.birthYear?.let { builder.setBirthYear(it) }
        input.regionCode?.let { builder.setRegionCode(it) }

        if (input.interestTagIds != null) {
            builder
                .addAllInterestTagIds(input.interestTagIds)
                .setUpdateInterestTags(true)
        }

        return try {
            stub.updateUserProfile(builder.build())
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
```

