## 6. DTO / Input 클래스

파일 위치: `graphql/src/main/kotlin/com/maum/backend/controller/profile/UserProfileDto.kt`

```kotlin
// GraphQL Input 매핑 데이터 클래스
data class UpdateUserProfileInput(
    val nickname: String?,
    val introduction: String?,
    val profileImageId: String?,
    val gender: GenderType?,
    val birthYear: Int?,
    val regionCode: String?,
    val interestTagIds: List<String>?,
)

enum class GenderType { MALE, FEMALE, OTHER }

// GraphQL Response 타입
data class UpdateUserProfilePayload(
    val profile: UserProfileResponse,
)

data class UserProfileResponse(
    val userId: String,
    val nickname: String,
    val introduction: String?,
    val profileImageUrl: String?,
    val gender: GenderType?,
    val birthYear: Int?,
    val regionCode: String?,
    val interestTags: List<InterestTagResponse>,
    val createdAt: String,
    val updatedAt: String,
)

data class InterestTagResponse(
    val id: String,
    val name: String,
)

// Proto -> Response 변환 확장 함수
fun UserProfile.toResponse() = UserProfileResponse(
    userId          = userId,
    nickname        = nickname,
    introduction    = introduction.ifBlank { null },
    profileImageUrl = profileImageUrl.ifBlank { null },
    gender          = when (gender) {
        GenderType.GENDER_TYPE_MALE   -> com.maum.backend.controller.profile.GenderType.MALE
        GenderType.GENDER_TYPE_FEMALE -> com.maum.backend.controller.profile.GenderType.FEMALE
        GenderType.GENDER_TYPE_OTHER  -> com.maum.backend.controller.profile.GenderType.OTHER
        else                          -> null
    },
    birthYear       = if (birthYear == 0) null else birthYear,
    regionCode      = regionCode.ifBlank { null },
    interestTags    = interestTagsList.map { InterestTagResponse(it.id, it.name) },
    createdAt       = createdAt,
    updatedAt       = updatedAt,
)
