    nickname        = nickname,
    introduction    = introduction.ifBlank { null },
    profileImageUrl = profileImageUrl.ifBlank { null },
    gender          = when (gender) {
        GenderType.GENDER_TYPE_MALE   -> com.maum.backend.controller.profile.GenderType.MALE
        GenderType.GENDER_TYPE_FEMALE -> com.maum.backend.controller.profile.GenderType.FEMALE
        GenderType.GENDER_TYPE_OTHER  -> com.maum.backend.controller.profile.GenderType.OTHER
        else                          -> null
    },
    birthYear       = if (birthYear == 0) null else birthYear,
    regionCode      = regionCode.ifBlank { null },
    interestTags    = interestTagsList.map { InterestTagResponse(it.id, it.name) },
    createdAt       = createdAt,
    updatedAt       = updatedAt,
)
